// NODO: HoneyPot_Context_Reducer
// OBIETTIVO: Estrarre dal HoneyPot i frammenti più utili per il nuovo prodotto

const item = $input.first().json;
const honeyPot = item.HoneyPot;
const fragments = honeyPot.knowledge_fragments || [];
const newProduct = item.new_product_block.identity;

// 1. DEFINIAMO LE KEYWORDS DI RICERCA
// Usiamo tags e nome del prodotto, più la categoria
const searchTerms = [
    ...newProduct.tags.map(t => t.toLowerCase()),
    newProduct.category.toLowerCase().replace('platform_', '').replace('_', ' '), // puliamo la categoria
    newProduct.item_name.toLowerCase()
];

// 2. SCORING DEI FRAMMENTI ESISTENTI
const scoredFragments = fragments.map(frag => {
    let score = 0;

    // Uniamo tutto il testo del frammento per la ricerca
    const content = (
        (frag.title || "") + " " + 
        (frag.summary || "") + " " + 
        JSON.stringify(frag.sections || []) + " " +
        JSON.stringify(frag.user_utterances || [])
    ).toLowerCase();

    // Cerchiamo match
    searchTerms.forEach(term => {
        if (term.length > 3 && content.includes(term)) { // Ignoriamo parole troppo corte
            score += 10;
        }
    });

    // Bonus se il titolo contiene la parola chiave principale (es. "Onboarding")
    if (newProduct.item_name.split(' ').some(word => word.length > 4 && (frag.title || "").toLowerCase().includes(word.toLowerCase()))) {
        score += 50;
    }

    return { fragment: frag, score: score };
});

// 3. SELEZIONE TOP 5 (o Fallback)
// Ordiniamo per punteggio
let topFragments = scoredFragments
    .filter(f => f.score > 0) // Prendiamo solo quelli che c'entrano qualcosa
    .sort((a, b) => b.score - a.score)
    .slice(0, 5)
    .map(f => f.fragment);

// FALLBACK: Se non abbiamo trovato NULLA di specifico (score > 0),
// prendiamo alcuni frammenti generici strutturali per dare almeno lo stile al modello.
if (topFragments.length === 0) {
    // Cerchiamo frammenti che spiegano "Come funziona" o "Chi è Giovanni"
    const fallbackKeywords = ["come funziona", "giovanni neve", "stile"];
    topFragments = fragments.filter(f => 
        fallbackKeywords.some(k => (f.title || "").toLowerCase().includes(k))
    ).slice(0, 3);
}

// 4. OUTPUT
return {
    json: {
        ...item,
        // Passiamo solo il necessario al prompt
        relevant_knowledge_context: topFragments.map(f => ({
            title: f.title,
            summary: f.summary,
            qa_pairs: f.sections // Le Q&A sono la parte più preziosa per lo stile
        }))
    }
};

// --- 1. CONFIGURAZIONE ---
const BOT_TOKEN = "8378810625:AAHK3Zya8qFKD4OzFBbwSTOAGolDeY7jiJQ";
const initData = $input.item.json.body._auth;

if (!initData) return { isValid: false, error: "Dato _auth mancante" };

// --- 2. LIBRERIA CRIPTOGRAFICA PURE JS (SHA-256 & HMAC) ---
const CryptoJS = (function() {
    function sha256(m) {
        var h = [0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19];
        var k = [0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5, 0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174, 0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da, 0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967, 0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85, 0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070, 0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3, 0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2];
        var b = Array.from(typeof m === 'string' ? new TextEncoder().encode(m) : m);
        var l = b.length * 8; b.push(0x80);
        while ((b.length * 8) % 512 !== 448) b.push(0);
        for (var i = 7; i >= 0; i--) b.push((l / Math.pow(2, i * 8)) & 0xff);
        for (var i = 0; i < b.length; i += 64) {
            var w = new Int32Array(64);
            for (var j = 0; j < 16; j++) w[j] = (b[i + j * 4] << 24) | (b[i + j * 4 + 1] << 16) | (b[i + j * 4 + 2] << 8) | (b[i + j * 4 + 3]);
            for (var j = 16; j < 64; j++) {
                var s0 = ((w[j - 15] >>> 7) | (w[j - 15] << 25)) ^ ((w[j - 15] >>> 18) | (w[j - 15] << 14)) ^ (w[j - 15] >>> 3);
                var s1 = ((w[j - 2] >>> 17) | (w[j - 2] << 15)) ^ ((w[j - 2] >>> 19) | (w[j - 2] << 13)) ^ (w[j - 2] >>> 10);
                w[j] = (w[j - 16] + s0 + w[j - 7] + s1) | 0;
            }
            var [a, c, d, e, f, g, i_h, j_h] = h;
            var v = [...h];
            for (var j = 0; j < 64; j++) {
                var S1 = ((v[4] >>> 6) | (v[4] << 26)) ^ ((v[4] >>> 11) | (v[4] << 21)) ^ ((v[4] >>> 25) | (v[4] << 7));
                var ch = (v[4] & v[5]) ^ (~v[4] & v[6]);
                var t1 = (v[7] + S1 + ch + k[j] + w[j]) | 0;
                var S0 = ((v[0] >>> 2) | (v[0] << 30)) ^ ((v[0] >>> 13) | (v[0] << 19)) ^ ((v[0] >>> 22) | (v[0] << 10));
                var maj = (v[0] & v[1]) ^ (v[0] & v[2]) ^ (v[1] & v[2]);
                var t2 = (S0 + maj) | 0;
                v.unshift((t1 + t2) | 0); v.splice(8); v[4] = (v[4] + t1) | 0;
            }
            for (var j = 0; j < 8; j++) h[j] = (h[j] + v[j]) | 0;
        }
        return h.reduce((acc, val) => acc.concat([(val >>> 24) & 0xff, (val >>> 16) & 0xff, (val >>> 8) & 0xff, val & 0xff]), []);
    }

    if (typeof TextEncoder === "undefined") {
        window.TextEncoder = function() {};
        TextEncoder.prototype.encode = function(s) {
            return new Uint8Array(unescape(encodeURIComponent(s)).split("").map(c => c.charCodeAt(0)));
        };
    }

    return {
        hmac: function(key, message) {
            var k = typeof key === 'string' ? Array.from(new TextEncoder().encode(key)) : key;
            var m = Array.from(new TextEncoder().encode(message));
            var b = 64;
            if (k.length > b) k = sha256(k);
            while (k.length < b) k.push(0);
            var ipad = k.map(x => x ^ 0x36);
            var opad = k.map(x => x ^ 0x5c);
            var inner = sha256(ipad.concat(m));
            return sha256(opad.concat(inner));
        }
    };
})();

// --- 3. LOGICA PARSING ---
const data = {};
initData.split('&').forEach(pair => {
    const [k, v] = pair.split('=');
    data[k] = decodeURIComponent(v);
});

const hashReceived = data.hash;
const checkString = Object.keys(data)
    .filter(k => k !== 'hash')
    .sort()
    .map(k => k + '=' + data[k])
    .join('\n');

// --- 4. CALCOLO HASH TELEGRAM ---
const secretKey = CryptoJS.hmac("WebAppData", BOT_TOKEN);
const computedHashBytes = CryptoJS.hmac(secretKey, checkString);
const computedHash = computedHashBytes.map(b => b.toString(16).padStart(2, '0')).join('');

// --- 5. CONTROLLO SCADENZA (MAX 1 ORA) ---
const now = Math.floor(Date.now() / 1000);
const authDate = parseInt(data.auth_date);
const isExpired = (now - authDate) > 3600; // Scade dopo 3600 secondi (1 ora)

// --- 6. RISULTATO FINALE ---
const isHashValid = (computedHash === hashReceived);

return {
    isValid: isHashValid && !isExpired,
    isExpired: isExpired,
    isHashValid: isHashValid,
    user: data.user ? JSON.parse(data.user) : null,
    auth_date_human: new Date(authDate * 1000).toLocaleString('it-IT'),
    debug: {
        time_diff_seconds: now - authDate,
        computed: computedHash,
        received: hashReceived
    }
};

const item = $input.first().json;
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&'; // La tua chiave segreta

// 1. Recupero del token
const rawAsh =
  item.ash ||
  item.query?.ash ||
  item.body?.ash ||
  item.body?.web_app_data?.data ||
  item.body?.message?.web_app_data?.data;

if (!rawAsh || typeof rawAsh !== "string") {
  throw new Error("ASH non trovato nell'input.");
}

// 2. Separazione Payload e Firma
const [encodedPayload, signatureReceived] = rawAsh.split(".");

if (!encodedPayload || !signatureReceived) {
  throw new Error("Formato ASH non valido.");
}

// 3. Decodifica e verifica integrità
let decodedPayload;
try {
    decodedPayload = Buffer.from(encodedPayload, "base64").toString("utf8");
} catch (e) {
    throw new Error("Errore decodifica Base64.");
}

// --- LOGICA DI VERIFICA FIRMA ---
function verifySignature(payload, secret, receivedSig) {
    let hash = 0;
    const combined = payload + secret;
    for (let i = 0; i < combined.length; i++) {
        hash = ((hash << 5) - hash) + combined.charCodeAt(i);
        hash = hash & hash; 
    }
    const expectedSig = Math.abs(hash).toString(16);
    return expectedSig === receivedSig;
}

if (!verifySignature(decodedPayload, SECRET_KEY, signatureReceived)) {
    // Se la firma non corrisponde, blocchiamo tutto qui!
    throw new Error("SICUREZZA: Firma ASH non valida o manomessa. Accesso negato.");
}
// --------------------------------

// 4. Estrazione ID (Solo se la firma è valida)
const parts = decodedPayload.split("|");

return [{
    json: {
        ...item,
        ids: {
            owner_id: parts[0],
            timestamp: parts[1],
            webhook: parts[2]
        }
    }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Rich_Product_Sheet_Message
// DESC: Visualizzazione completa dati estratti e blocco UI
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero dati dal blocco prodotto
const block = item.body.new_product_block || {};
const ident = block.identity || {};
const price = block.pricing || {};
const ops = block.operations || {};
const marketing = block.relations?.marketing_info || {};
const owner = item.owner_data || {};

const chatId = owner.chat_id;
const messageId = item.body.msg_id;

// 2. Rilevamento Lingua
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: "📝 <b>IDENTITÀ PROCEDURA ESTRATTA</b>",
    label_name: "📋 Nome:",
    label_type: "🗂️ Tipo:",
    label_desc: "📖 Descrizione:",
    label_price: "💰 Valore Commerciale:",
    label_time: "⏳ Esecuzione stimata:",
    label_target: "👥 Target:",
    label_tags: "🏷️ Tag:",
    next_phase: "⚙️ <b>PROSSIMA FASE: Scrittura Tecnica del Blueprint</b>",
    warning: "⚠️ <b>Nota:</b> Questa operazione è complessa e richiede <b>qualche minuto</b> per essere completata.\n\n<i>Il sistema rimarrà impegnato fino al termine della scrittura tecnica. Attendi senza inviare altri comandi.</i>"
  },
  en: {
    title: "📝 <b>PROCEDURE IDENTITY EXTRACTED</b>",
    label_name: "📋 Name:",
    label_type: "🗂️ Type:",
    label_desc: "📖 Description:",
    label_price: "💰 Commercial Value:",
    label_time: "⏳ Est. Execution:",
    label_target: "👥 Target:",
    label_tags: "🏷️ Tags:",
    next_phase: "⚙️ <b>NEXT PHASE: Technical Blueprint Writing</b>",
    warning: "⚠️ <b>Note:</b> This is a complex operation and will take <b>a few minutes</b> to complete.\n\n<i>The system will remain busy until the technical writing is finished. Please wait and do not send other commands.</i>"
  }
}[lang];

// 3. Costruzione dinamica del corpo (Solo dati presenti)
let rows = [];
rows.push(`${t.label_name} <b>${ident.item_name}</b>`);
rows.push(`${t.label_type} <code>${ident.item_type}</code>`);

if (ident.description?.long) {
    rows.push(`\n${t.label_desc}\n<i>${ident.description.long}</i>\n`);
}

// Mostra Prezzo solo se > 0
if (price.base_price > 0) {
    rows.push(`${t.label_price} <b>${price.base_price} ${price.currency}</b>`);
}

// Mostra Tempo solo se valorizzato
if (ops.fulfillment_time?.value) {
    rows.push(`${t.label_time} <b>${ops.fulfillment_time.value} ${ops.fulfillment_time.unit}</b>`);
}

// Target Audience
if (marketing.target_audience_tags?.length > 0) {
    rows.push(`${t.label_target} <code>${marketing.target_audience_tags.join(", ")}</code>`);
}

// Tag tecnici
if (ident.tags?.length > 0) {
    rows.push(`${t.label_tags} #${ident.tags.join(" #")}`);
}

// 4. Formattazione finale del messaggio
const messageText = `
${t.title}
━━━━━━━━━━━━━━━━━━━━
${rows.join("\n")}

━━━━━━━━━━━━━━━━━━━━
${t.next_phase}

${t.warning}`;

// 5. Payload Telegram
return [{
  json: {
    ...item,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageId,
      text: messageText,
      parse_mode: "HTML"
    }
  }
}];

// ════════════════════════════════════════════════════════━━━━━━━━
// NODO: Prepare_System_Failure_Notification (EDIT_MODE)
// ════════════════════════════════════════━━━━━━━━━━━━━━━━━━━━━━━━

const item = $input.first().json;
const owner = item.owner_data || {};
const chatId = owner.chat_id;
const messageId = item.body.msg_id; // Recupero message_id originale
const itemName = item.new_product_block?.identity?.item_name || "Asset";

const lang = (owner.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';

const t = {
    it: {
        title: "❌ <b>EXECUTION ERROR</b>",
        body: `Errore durante la generazione dei parametri per: <b>${itemName}</b>.`,
        status: "STATO: <code>AI_GENERATION_FAILED</code>",
        action: "L'indice dei dati non è stato aggiornato. Ripetere l'operazione.",
        btn_dash: "🏠 HUB PRINCIPALE"
    },
    en: {
        title: "❌ <b>EXECUTION ERROR</b>",
        body: `Error during parameter generation for: <b>${itemName}</b>.`,
        status: "STATUS: <code>AI_GENERATION_FAILED</code>",
        action: "Data index not updated. Please retry the operation.",
        btn_dash: "🏠 MAIN HUB"
    }
}[lang];

return [{
    json: {
        ...item,
        telegramApiPayload: {
            method: "editMessageText", // Trasformato in edit
            chat_id: chatId,
            message_id: messageId,
            text: `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n${t.body}\n\n${t.status}\n\n${t.action}`,
            parse_mode: "HTML",
            reply_markup: {
                inline_keyboard: [
                    [{ text: t.btn_dash, callback_data: "open_agent_control_center" }]
                ]
            }
        }
    }
}];
